function ReviewAcademicReports({ state }) {
  const subjectAverages = Object.entries(state.students.reduce((acc, student) => {
    Object.entries(student.marks).forEach(([subject, score]) => {
      acc[subject] = acc[subject] || { total: 0, count: 0 };
      acc[subject].total += score;
      acc[subject].count += 1;
    });
    return acc;
  }, {})).map(([subject, metric]) => ({ subject, average: Math.round(metric.total / metric.count) }));
  const average = Math.round(subjectAverages.reduce((sum, item) => sum + item.average, 0) / subjectAverages.length);

  return panelWrapper('Review Academic Reports', 'Visual tracking analytics dashboard displaying grade curves and averages.', (
    <>
      <div className="metrics-grid"><div className="metric-card"><div>Average</div><div>{average}%</div></div></div>
      <div className="grid-cards">{subjectAverages.map(item => <div key={item.subject} className="stat-card"><div>{item.subject}</div><div>{item.average}%</div></div>)}</div>
    </>
  ));
}

