function PayStudentFees({ state, setState, user }) {
  const pendingFees = state.financials.fees.filter(fee => fee.status !== 'Paid');
  const [selectedFeeId, setSelectedFeeId] = useState(pendingFees[0]?.id || '');
  const selectedFee = pendingFees.find(fee => fee.id === selectedFeeId);

  const handleSuccess = (feeId) => {
    setState(prev => ({
      ...prev,
      financials: {
        ...prev.financials,
        fees: prev.financials.fees.map(fee => fee.id === feeId ? { ...fee, status: 'Paid' } : fee)
      },
      notifications: [{
        id: Date.now(),
        message: `[Fee payment successful] Payment processed for ${selectedFee?.student}.`,
        channels: ['Accountant', 'Parent'],
        time: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })
      }, ...prev.notifications]
    }));
  };

  return panelWrapper('Pay Fees', 'Secure student invoice checkout with Stripe card payment integration.', (
    <div className="grid-gap">
      <div className="table-card">
        <table>
          <thead><tr><th>Student</th><th>Fee Type</th><th>Amount</th><th>Due Date</th><th>Status</th></tr></thead>
          <tbody>{pendingFees.map(fee => (
            <tr key={fee.id} className={fee.id === selectedFeeId ? 'selected-row' : ''}>
              <td>{fee.student}</td>
              <td>{fee.type}</td>
              <td>₹{fee.amount.toLocaleString()}</td>
              <td>{fee.dueDate}</td>
              <td>{fee.status}</td>
              <td><button type="button" onClick={() => setSelectedFeeId(fee.id)}>Select</button></td>
            </tr>
          ))}</tbody>
        </table>
      </div>
      {selectedFee ? (
        <div className="panel-card">
          <h3>Pay ₹{selectedFee.amount.toLocaleString()} for {selectedFee.student}</h3>
          <StripeCheckoutForm fee={selectedFee} onSuccess={handleSuccess} user={user} />
        </div>
      ) : (
        <div className="empty-state">No pending student fees available for payment.</div>
      )}
    </div>
  ));
}

function PayChildFees({ state, setState, user }) {
